7049                                    const Instruction *MainOp,
7050                                    const Instruction *AltOp,
7051                                    const TargetLibraryInfo &TLI) {
7052   if (auto *MainCI = dyn_cast<CmpInst>(MainOp)) {
7053     auto *AltCI = cast<CmpInst>(AltOp);
7054     CmpInst::Predicate MainP = MainCI->getPredicate();
7055     CmpInst::Predicate AltP = AltCI->getPredicate();
7056     assert(MainP != AltP && "Expected different main/alternate predicates.");
7057     auto *CI = cast<CmpInst>(I);
7058     if (isCmpSameOrSwapped(MainCI, CI, TLI))
7059       return false;
7060     if (isCmpSameOrSwapped(AltCI, CI, TLI))
7061       return true;
7062     CmpInst::Predicate P = CI->getPredicate();
7063     CmpInst::Predicate SwappedP = CmpInst::getSwappedPredicate(P);
7064 
7065     assert((MainP == P || AltP == P || MainP == SwappedP || AltP == SwappedP) &&
7066            "CmpInst expected to match either main or alternate predicate or "
7067            "their swap.");
7068     (void)AltP;
7069     return MainP != P && MainP != SwappedP;
7070   }
7071   return I->getOpcode() == AltOp->getOpcode();
7072 }
