7095       return CI->getValue().isNegatedPowerOf2();
7096     return false;
7097   });
7098 
7099   TTI::OperandValueKind VK = TTI::OK_AnyValue;
7100   if (IsConstant && IsUniform)
7101     VK = TTI::OK_UniformConstantValue;
7102   else if (IsConstant)
7103     VK = TTI::OK_NonUniformConstantValue;
7104   else if (IsUniform)
7105     VK = TTI::OK_UniformValue;
