3791 /// Reorders the given \p Reuses mask according to the given \p Mask. \p Reuses
3792 /// contains original mask for the scalars reused in the node. Procedure
3793 /// transform this mask in accordance with the given \p Mask.
3794 static void reorderReuses(SmallVectorImpl<int> &Reuses, ArrayRef<int> Mask) {
3795   assert(!Mask.empty() && Reuses.size() == Mask.size() &&
3796          "Expected non-empty mask.");
3797   SmallVector<int> Prev(Reuses.begin(), Reuses.end());
3798   Prev.swap(Reuses);
3799   for (unsigned I = 0, E = Prev.size(); I < E; ++I)
3800     if (Mask[I] != PoisonMaskElem)
3801       Reuses[Mask[I]] = Prev[I];
